use crate::domain::WorkflowDefinition;
use crate::error::{Result, SymphonyError};
use std::path::Path;

/// Parse a WORKFLOW.md file into a `WorkflowDefinition`.
///
/// The file may optionally contain YAML front matter delimited by `---`.
/// If no delimiter is present, the entire file becomes the prompt template
/// and the config defaults to an empty mapping.
///
/// # Errors
/// Returns `SymphonyError::WorkflowParseError` for IO/parse failures and
/// `SymphonyError::WorkflowFrontMatterNotAMap` if the YAML block is not a
/// mapping.
pub fn parse_workflow(_path: &Path) -> Result<WorkflowDefinition> {
    Err(SymphonyError::WorkflowParseError(
        "not yet implemented".to_string(),
    ))
}

// Config layer — stub, will be fully implemented in T04.

use crate::domain::ServiceConfig;
use crate::error::{Result, SymphonyError};

/// Derive a typed `ServiceConfig` from the raw YAML front-matter map
/// extracted by `parse_workflow`.
///
/// Applies spec §5.3 defaults, resolves `$ENV_VAR` references, and expands
/// leading `~` in path fields.
pub fn from_workflow(_config: &serde_yaml::Value) -> Result<ServiceConfig> {
    Err(SymphonyError::InvalidWorkflowConfig(
        "not yet implemented".to_string(),
    ))
}

/// Validate a `ServiceConfig` for required fields and acceptable values.
///
/// Returns `Err(SymphonyError::InvalidWorkflowConfig(_))` for any
/// structural problem (missing api_key, unknown tracker kind, etc.).
pub fn validate(_config: &ServiceConfig) -> Result<()> {
    Err(SymphonyError::InvalidWorkflowConfig(
        "not yet implemented".to_string(),
    ))
}

// WorkflowStore — stub, will be fully implemented in T05.

use crate::domain::{ServiceConfig, WorkflowDefinition};
use crate::error::{Result, SymphonyError};
use std::path::{Path, PathBuf};

/// Owns the parsed WORKFLOW.md and its derived `ServiceConfig`, and hot-reloads
/// the file when it changes on disk.
///
/// The store guarantees last-known-good semantics: a reload failure (parse error,
/// invalid config) leaves the previous config in place.
pub struct WorkflowStore {
    _path: PathBuf,
}

impl WorkflowStore {
    /// Construct a `WorkflowStore` from a WORKFLOW.md path.
    ///
    /// Parses the file immediately and starts a background watcher.
    pub fn new(_path: &Path) -> Result<Self> {
        Err(SymphonyError::WorkflowParseError(
            "not yet implemented".to_string(),
        ))
    }

    /// Return a snapshot of the current `(WorkflowDefinition, ServiceConfig)`.
    pub fn effective_config(&self) -> (WorkflowDefinition, ServiceConfig) {
        unimplemented!("not yet implemented")
    }
}

