    fn default() -> Self {
        Self {
            kind: None,
            endpoint: "https://api.linear.app/graphql".to_string(),
            api_key: None,
            project_slug: None,
            assignee: None,
            active_states: vec!["Todo".to_string(), "In Progress".to_string()],
            terminal_states: vec![
                "Closed".to_string(),
                "Cancelled".to_string(),
                "Canceled".to_string(),
                "Duplicate".to_string(),
                "Done".to_string(),
            ],
        }
    }
}

/// Polling configuration (spec §5.3.2).
#[derive(Debug, Clone)]
pub struct PollingConfig {
    pub interval_ms: u64,
